exercise.solution:
// Expected: sync 1, sync 2, microtask 1, extra microtask, timeout

console.log('sync 1');

setTimeout(() => {
  console.log('timeout');
}, 0);

Promise.resolve()
  .then(() => {
    console.log('microtask 1');
    Promise.resolve().then(() => {
      console.log('extra microtask');
    });
  });

console.log('sync 2');
